Rules.InvariantScript:
ForAll(
    Filter(
        'Sous-demandes d''envoi matériel',
        'Demande d''envoi associée'.Value = IDRéceptionMultiple,
        Statut.Value = "Soldée"
    ),
    If(
        IsEmpty(
            Filter(
                CollectionRéceptionMultipleMatériel,
                ID = ThisRecord.Value,
                Liste = "Matériels"
            )
        ),
        Collect(
            CollectionRéceptionMultipleMatériel,
            {
                Value: ID,
                Liste: "Matériels"
            }
        )
    )
)
